mapper.select:
SELECT id, clinic_code, clinic_name, principal, phone, email, region, address, license_no, introduction, created_at, updated_at, deleted FROM clinic_info WHERE deleted = 0
AND (clinic_name LIKE CONCAT('%', #{keyword}, '%') OR phone LIKE CONCAT('%', #{keyword}, '%') OR principal LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE clinic_info
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
